%[text] # Model of vehicle dynamics

function X_dot = aircraft_3dof_wind_dynamics(t, X, U, S_ref, CD0, k)
% 3-DOF point-mass aircraft dynamics with wind disturbance
%
% State:
%   X = [x; h; V; gamma; m]
%       x      : horizontal ground position [m]
%       h      : altitude [m]
%       V      : air-relative speed [m/s]
%       gamma  : air-relative flight path angle [rad]
%       m      : mass [kg]
%
% Control:
%   U = [T; CL]
%       T      : thrust [N]
%       CL     : lift coefficient [-]
%
% Output:
%   X_dot = [x_dot; h_dot; V_dot; gamma_dot; m_dot]

    if nargin < 5
        CD0 = 0.02;
    end
    if nargin < 6
        k = 0.045;
    end

    g = 9.81; % [m/s^2]

    % Unpack state
    x     = X(1);
    h     = X(2);
    V     = X(3);
    gamma = X(4);
    m     = X(5);

    % Unpack control
    T  = U(1);
    CL = U(2);

    % Basic protection
    V = max(V, 1e-3);
    m = max(m, 1e-3);

    % Atmosphere and wind
    rho = atmosphere_density(h);
    [Wx, Wh] = wind_field(x, h, t);

    % Aerodynamic forces
    CD = drag_polar(CL, CD0, k);
    q  = 0.5 * rho * V^2;

    L = q * S_ref * CL;
    D = q * S_ref * CD;

    % Ground-relative kinematics with wind disturbance
    x_dot = V * cos(gamma) + Wx;
    h_dot = V * sin(gamma) + Wh;

    % Air-relative dynamics
    V_dot     = (T - D - m * g * sin(gamma)) / m;
    gamma_dot = (L - m * g * cos(gamma)) / (m * V);

    % Fuel burn
    m_dot = -fuel_flow_model(T, h, V);

    X_dot = [x_dot; h_dot; V_dot; gamma_dot; m_dot];
end


function rho = atmosphere_density(h)
% Simple exponential atmosphere
[rho0, ~] = atmos(h);  % density at altitude h

    h_scale = 8500.0;  % [m]
    rho = rho0 * exp(-h / h_scale);
end


function [Wx, Wh] = wind_field(x, h, t)
% Wind disturbance in inertial coordinates
% Wx : horizontal wind component [m/s], positive tailwind
% Wh : vertical wind component [m/s], positive upward

    %#ok<INUSD>
    Wx = 0.0;
    Wh = 0.0;
end


function CD = drag_polar(CL, CD0, k)
% Parabolic drag polar
    CD = CD0 + k * CL^2;
end


function mdot = fuel_flow_model(T, h, V)
% Simple fuel flow model
% Returns fuel flow in [kg/s]

    %#ok<INUSD>
    tsfc = 1.6e-5; % [kg/(N*s)]
    mdot = tsfc * max(T, 0.0);
end

%%
%[text] ## Simulation of vehicle
% Parameters
S_ref = 122.6;     % [m^2]
CD0   = 0.02;
k     = 0.045;

% Initial state: X = [x; h; V; gamma; m]
X0 = [ ...
    0.0;        % x [m]
    10000.0;    % h [m]
    220.0;      % V [m/s]
   -0.03;       % gamma [rad]
    65000.0];   % m [kg]

% Constant control: U = [T; CL]
U = [ ...
    20000.0;    % T [N]
    0.5];       % CL [-]

% Time span
tspan = [0 600];   % [s]

% Dynamics wrapper for ode45
f = @(t, X) aircraft_3dof_wind_dynamics(t, X, U, S_ref, CD0, k);

% Integrate
opts = odeset('RelTol',1e-8,'AbsTol',1e-9);
[t, X] = ode45(f, tspan, X0, opts);

% Unpack states
x     = X(:,1);
h     = X(:,2);
V     = X(:,3);
gamma = X(:,4);
m     = X(:,5);

% Optional derived quantities
g = 9.81;
E = 0.5 .* m .* V.^2 + m .* g .* h;     % total mechanical energy [J]
gamma_deg = rad2deg(gamma);

%% Plot 1: trajectory in x-h plane
figure; %[output:8b0ac9af]
plot(x/1000, h/1000, 'LineWidth', 1.5); %[output:8b0ac9af]
grid on; %[output:8b0ac9af]
xlabel('Downrange x [km]'); %[output:8b0ac9af]
ylabel('Altitude h [km]'); %[output:8b0ac9af]
title('Aircraft Ground Track in Vertical Plane'); %[output:8b0ac9af]

%% Plot 2: speed and flight path angle vs time
figure; %[output:69bb09c3]
yyaxis left %[output:69bb09c3]
plot(t, V, 'LineWidth', 1.5); %[output:69bb09c3]
ylabel('Airspeed V [m/s]'); %[output:69bb09c3]

yyaxis right %[output:69bb09c3]
plot(t, gamma_deg, 'LineWidth', 1.5); %[output:69bb09c3]
ylabel('Flight Path Angle \gamma [deg]'); %[output:69bb09c3]

grid on; %[output:69bb09c3]
xlabel('Time [s]'); %[output:69bb09c3]
title('Airspeed and Flight Path Angle vs Time'); %[output:69bb09c3]

%% Plot 3: mass and energy vs time
figure; %[output:0b6beab8]
yyaxis left %[output:0b6beab8]
plot(t, m, 'LineWidth', 1.5); %[output:0b6beab8]
ylabel('Mass [kg]'); %[output:0b6beab8]

yyaxis right %[output:0b6beab8]
plot(t, E/1e9, 'LineWidth', 1.5); %[output:0b6beab8]
ylabel('Mechanical Energy [GJ]'); %[output:0b6beab8]

grid on; %[output:0b6beab8]
xlabel('Time [s]'); %[output:0b6beab8]
title('Mass and Total Mechanical Energy vs Time'); %[output:0b6beab8]

%% Plot 4: altitude vs time
figure; %[output:5b93f902]
plot(t, h, 'LineWidth', 1.5); %[output:5b93f902]
grid on; %[output:5b93f902]
xlabel('Time [s]'); %[output:5b93f902]
ylabel('Altitude [m]'); %[output:5b93f902]
title('Altitude vs Time'); %[output:5b93f902]

